<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Snake</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            background: #0f0f1a;
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
            font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
            user-select: none;
            -webkit-user-select: none;
        }

        .container {
            text-align: center;
            padding: 20px;
        }

        h1 {
            color: #e2e8f0;
            font-size: 2rem;
            font-weight: 700;
            margin-bottom: 12px;
            letter-spacing: 0.05em;
            text-transform: uppercase;
        }

        .score-panel {
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 8px;
            margin-bottom: 16px;
            color: #94a3b8;
            font-size: 1.1rem;
            font-weight: 500;
        }

        #score {
            color: #fbbf24;
            font-weight: 700;
            font-size: 1.4rem;
            min-width: 40px;
            display: inline-block;
            transition: transform 0.1s ease;
        }

        #score.pop {
            transform: scale(1.3);
        }

        canvas#snake {
            display: block;
            margin: 0 auto 16px;
            border: 2px solid #334155;
            border-radius: 8px;
            box-shadow: 0 0 30px rgba(74, 222, 128, 0.08), 0 8px 32px rgba(0, 0, 0, 0.4);
            background: #16213e;
            width: 400px;
            height: 400px;
        }

        .controls {
            display: flex;
            gap: 12px;
            justify-content: center;
            flex-wrap: wrap;
        }

        button {
            padding: 10px 24px;
            font-size: 0.95rem;
            font-weight: 600;
            letter-spacing: 0.03em;
            border: none;
            border-radius: 6px;
            cursor: pointer;
            transition: background 0.2s, transform 0.1s, box-shadow 0.2s;
            outline: none;
            text-transform: uppercase;
        }

        button:active {
            transform: scale(0.96);
        }

        #start {
            background: #16a34a;
            color: #fff;
            box-shadow: 0 4px 14px rgba(22, 163, 74, 0.35);
        }
        #start:hover {
            background: #22c55e;
            box-shadow: 0 6px 20px rgba(34, 197, 94, 0.45);
        }

        #pause {
            background: #ca8a04;
            color: #fff;
            box-shadow: 0 4px 14px rgba(202, 138, 4, 0.35);
        }
        #pause:hover {
            background: #eab308;
            box-shadow: 0 6px 20px rgba(234, 179, 8, 0.45);
        }

        #reset {
            background: #475569;
            color: #e2e8f0;
            box-shadow: 0 4px 14px rgba(71, 85, 105, 0.35);
        }
        #reset:hover {
            background: #64748b;
            box-shadow: 0 6px 20px rgba(100, 116, 139, 0.45);
        }

        .hint {
            color: #64748b;
            font-size: 0.8rem;
            margin-top: 14px;
            letter-spacing: 0.02em;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>Snake</h1>
        <div class="score-panel">Score:&nbsp;<span id="score">0</span></div>
        <canvas id="snake" width="400" height="400"></canvas>
        <div class="controls">
            <button id="start">Start</button>
            <button id="pause">Pause</button>
            <button id="reset">Reset</button>
        </div>
        <p class="hint">Arrow keys to steer &bull; Avoid walls &amp; yourself</p>
    </div>

    <script>
        (function() {
            // ──────────────────────────────────────
            // Game constants & state
            // ──────────────────────────────────────
            const CELL_SIZE = 20;
            const GRID_W = 20;
            const GRID_H = 20;
            const CANVAS_SIZE = 400; // 20 * 20 = 400

            let snake = []; // head-first: [[x,y], [x,y], ...]
            let food = null; // [x, y] | null
            let dir = 'right'; // current movement direction
            let nextDir = 'right'; // queued direction (applied on tick)
            let alive = true;
            let score = 0;
            let intervalId = null;
            const TICK_MS = 140;

            const opposites = {
                'up': 'down',
                'down': 'up',
                'left': 'right',
                'right': 'left'
            };

            const validDirs = ['up', 'down', 'left', 'right'];

            // ──────────────────────────────────────
            // Canvas & drawing
            // ──────────────────────────────────────
            const canvas = document.getElementById('snake');
            const ctx = canvas.getContext('2d');
            const scoreEl = document.getElementById('score');

            function draw() {
                ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

                // Board background
                ctx.fillStyle = '#16213e';
                ctx.fillRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

                // Grid lines
                ctx.strokeStyle = '#1e3050';
                ctx.lineWidth = 0.5;
                for (let x = 0; x <= GRID_W; x++) {
                    ctx.beginPath();
                    ctx.moveTo(x * CELL_SIZE, 0);
                    ctx.lineTo(x * CELL_SIZE, GRID_H * CELL_SIZE);
                    ctx.stroke();
                }
                for (let y = 0; y <= GRID_H; y++) {
                    ctx.beginPath();
                    ctx.moveTo(0, y * CELL_SIZE);
                    ctx.lineTo(GRID_W * CELL_SIZE, y * CELL_SIZE);
                    ctx.stroke();
                }

                // Food
                if (food) {
                    const fx = food[0] * CELL_SIZE + CELL_SIZE / 2;
                    const fy = food[1] * CELL_SIZE + CELL_SIZE / 2;

                    // Soft glow
                    const glowGrad = ctx.createRadialGradient(fx, fy, CELL_SIZE * 0.3, fx, fy, CELL_SIZE * 0.85);
                    glowGrad.addColorStop(0, 'rgba(239, 68, 68, 0.55)');
                    glowGrad.addColorStop(1, 'rgba(239, 68, 68, 0)');
                    ctx.fillStyle = glowGrad;
                    ctx.beginPath();
                    ctx.arc(fx, fy, CELL_SIZE * 0.85, 0, Math.PI * 2);
                    ctx.fill();

                    // Main food dot
                    ctx.fillStyle = '#ef4444';
                    ctx.beginPath();
                    ctx.arc(fx, fy, CELL_SIZE * 0.38, 0, Math.PI * 2);
                    ctx.fill();

                    // Highlight
                    ctx.fillStyle = 'rgba(255,255,255,0.45)';
                    ctx.beginPath();
                    ctx.arc(fx - CELL_SIZE * 0.1, fy - CELL_SIZE * 0.12, CELL_SIZE * 0.13, 0, Math.PI * 2);
                    ctx.fill();
                }

                // Snake (draw tail-to-head so head renders on top)
                for (let i = snake.length - 1; i >= 0; i--) {
                    const seg = snake[i];
                    const sx = seg[0] * CELL_SIZE + 1.5;
                    const sy = seg[1] * CELL_SIZE + 1.5;
                    const size = CELL_SIZE - 3;
                    const radius = 5;

                    if (i === 0) {
                        // Head – brighter green
                        const headGrad = ctx.createLinearGradient(sx, sy, sx + size, sy + size);
                        headGrad.addColorStop(0, '#4ade80');
                        headGrad.addColorStop(1, '#22c55e');
                        ctx.fillStyle = headGrad;
                        ctx.beginPath();
                        ctx.roundRect(sx, sy, size, size, radius);
                        ctx.fill();

                        // Eyes
                        const cx = sx + size / 2;
                        const cy = sy + size / 2;
                        const eyeOff = 3.5;
                        const eyeR = 2.8;
                        let e1x, e1y, e2x, e2y;
                        switch (dir) {
                            case 'right':
                                e1x = cx + eyeOff;
                                e1y = cy - eyeOff;
                                e2x = cx + eyeOff;
                                e2y = cy + eyeOff;
                                break;
                            case 'left':
                                e1x = cx - eyeOff;
                                e1y = cy - eyeOff;
                                e2x = cx - eyeOff;
                                e2y = cy + eyeOff;
                                break;
                            case 'up':
                                e1x = cx - eyeOff;
                                e1y = cy - eyeOff;
                                e2x = cx + eyeOff;
                                e2y = cy - eyeOff;
                                break;
                            case 'down':
                                e1x = cx - eyeOff;
                                e1y = cy + eyeOff;
                                e2x = cx + eyeOff;
                                e2y = cy + eyeOff;
                                break;
                        }
                        ctx.fillStyle = '#ffffff';
                        ctx.beginPath();
                        ctx.arc(e1x, e1y, eyeR, 0, Math.PI * 2);
                        ctx.fill();
                        ctx.beginPath();
                        ctx.arc(e2x, e2y, eyeR, 0, Math.PI * 2);
                        ctx.fill();

                        // Pupils
                        ctx.fillStyle = '#0f172a';
                        ctx.beginPath();
                        ctx.arc(e1x, e1y, eyeR * 0.55, 0, Math.PI * 2);
                        ctx.fill();
                        ctx.beginPath();
                        ctx.arc(e2x, e2y, eyeR * 0.55, 0, Math.PI * 2);
                        ctx.fill();
                    } else {
                        // Body segment
                        const alpha = 1 - (i / (snake.length + 8)) * 0.35;
                        ctx.fillStyle = `rgba(74, 222, 128, ${alpha.toFixed(2)})`;
                        ctx.beginPath();
                        ctx.roundRect(sx, sy, size, size, radius);
                        ctx.fill();

                        // Subtle inner highlight
                        ctx.fillStyle = `rgba(255,255,255,${(alpha * 0.12).toFixed(2)})`;
                        ctx.beginPath();
                        ctx.roundRect(sx + 2, sy + 2, size - 4, size - 4, radius - 1);
                        ctx.fill();
                    }
                }

                // Game-over overlay
                if (!alive) {
                    ctx.fillStyle = 'rgba(0, 0, 0, 0.65)';
                    ctx.fillRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

                    ctx.fillStyle = '#f1f5f9';
                    ctx.font = 'bold 34px "Segoe UI", "Helvetica Neue", Arial, sans-serif';
                    ctx.textAlign = 'center';
                    ctx.textBaseline = 'middle';
                    ctx.fillText('GAME OVER', CANVAS_SIZE / 2, CANVAS_SIZE / 2 - 12);

                    ctx.fillStyle = '#fbbf24';
                    ctx.font = '18px "Segoe UI", "Helvetica Neue", Arial, sans-serif';
                    ctx.fillText('Score: ' + score, CANVAS_SIZE / 2, CANVAS_SIZE / 2 + 24);
                }

                // Update DOM score
                scoreEl.textContent = score;
            }

            // ──────────────────────────────────────
            // Helpers
            // ──────────────────────────────────────
            function randomFreeCell() {
                const occupied = new Set(snake.map(s => s[0] + ',' + s[1]));
                const free = [];
                for (let x = 0; x < GRID_W; x++) {
                    for (let y = 0; y < GRID_H; y++) {
                        if (!occupied.has(x + ',' + y)) {
                            free.push([x, y]);
                        }
                    }
                }
                if (free.length === 0) return null;
                return free[Math.floor(Math.random() * free.length)];
            }

            function popScoreAnimation() {
                scoreEl.classList.add('pop');
                setTimeout(() => scoreEl.classList.remove('pop'), 120);
            }

            // ──────────────────────────────────────
            // Core game functions
            // ──────────────────────────────────────
            function reset() {
                if (intervalId) {
                    clearInterval(intervalId);
                    intervalId = null;
                }
                snake = [
                    [10, 10], // head
                    [9, 10],
                    [8, 10]
                ];
                dir = 'right';
                nextDir = 'right';
                alive = true;
                score = 0;
                food = randomFreeCell();
                draw();
            }

            function tick() {
                if (!alive) return;

                // Apply queued direction
                dir = nextDir;

                // Compute new head
                const head = snake[0];
                let newHead;
                switch (dir) {
                    case 'up':
                        newHead = [head[0], head[1] - 1];
                        break;
                    case 'down':
                        newHead = [head[0], head[1] + 1];
                        break;
                    case 'left':
                        newHead = [head[0] - 1, head[1]];
                        break;
                    case 'right':
                        newHead = [head[0] + 1, head[1]];
                        break;
                    default:
                        return;
                }

                // Wall collision
                if (newHead[0] < 0 || newHead[0] >= GRID_W || newHead[1] < 0 || newHead[1] >= GRID_H) {
                    alive = false;
                    draw();
                    return;
                }

                // Food check
                const growing = food !== null && newHead[0] === food[0] && newHead[1] === food[1];

                // Self-collision: if growing, check entire body; if not, exclude tail (it will move away)
                const collisionSource = growing ? snake : snake.slice(0, -1);
                for (const seg of collisionSource) {
                    if (seg[0] === newHead[0] && seg[1] === newHead[1]) {
                        alive = false;
                        draw();
                        return;
                    }
                }

                // Move: add new head
                snake.unshift(newHead);

                if (growing) {
                    score++;
                    popScoreAnimation();
                    food = randomFreeCell();
                    // If board is completely full, no food – game continues until collision
                } else {
                    snake.pop();
                }

                draw();
            }

            function setDir(d) {
                if (!validDirs.includes(d)) return;
                // Ignore 180° reversal against current movement direction
                if (opposites[d] === dir) return;
                nextDir = d;
            }

            function setFood(x, y) {
                food = [x, y];
                draw();
            }

            function getSnake() {
                return snake.map(s => [s[0], s[1]]);
            }

            function getFood() {
                return food ? [food[0], food[1]] : null;
            }

            function isAlive() {
                return alive;
            }

            function getScore() {
                return score;
            }

            // ──────────────────────────────────────
            // Expose API on window
            // ──────────────────────────────────────
            window.game = {
                w: GRID_W,
                h: GRID_H,
                reset: reset,
                tick: tick,
                setDir: setDir,
                setFood: setFood,
                snake: getSnake,
                food: getFood,
                alive: isAlive,
                score: getScore,
            };

            // ──────────────────────────────────────
            // Button handlers
            // ──────────────────────────────────────
            document.getElementById('start').addEventListener('click', function() {
                if (!alive) reset();
                if (intervalId) clearInterval(intervalId);
                intervalId = setInterval(function() {
                    tick();
                    if (!alive && intervalId) {
                        clearInterval(intervalId);
                        intervalId = null;
                    }
                }, TICK_MS);
            });

            document.getElementById('pause').addEventListener('click', function() {
                if (intervalId) {
                    clearInterval(intervalId);
                    intervalId = null;
                }
            });

            document.getElementById('reset').addEventListener('click', function() {
                reset();
            });

            // ──────────────────────────────────────
            // Keyboard controls
            // ──────────────────────────────────────
            document.addEventListener('keydown', function(e) {
                const keyMap = {
                    'ArrowUp': 'up',
                    'ArrowDown': 'down',
                    'ArrowLeft': 'left',
                    'ArrowRight': 'right'
                };
                const mapped = keyMap[e.key];
                if (mapped) {
                    e.preventDefault();
                    setDir(mapped);
                }
            });

            // ──────────────────────────────────────
            // Initialise
            // ──────────────────────────────────────
            reset();
        })();
    </script>
</body>
</html>
